#include<bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) meke_pair(x,y);
#define inf 0x3f3f3f3f
using namespace std;
inline ll read(){
    ll x=0,f=1;
    char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
    while(ch>='0'&&ch<='9')x=x*10+ch-'0',ch=getchar();
    return x*f;
}
void write(ll x){
    if(x<0)putchar('-'),x=-x;
    if(x>9)write(x/10);
    putchar(x%10+'0');return;
}
const ll INF=1e12;
int n;stack<char> st;
string c;ll s;
int main(void){
	//freopen("xx.in","r",stdin);
	//freopen("xx.out","w",stdout);
	n=read(),s=read(),cin>>c;
	for(int i=0;i<n;++i)
	{
		if(c[i]=='U')
		{
			if(s==1) continue;
			if(st.size())
			{
				st.pop();
				continue;
			}
			s>>=1;
		}
		else if(c[i]=='L')
		{
			if((s<<1)>INF)
			{
				st.push('L');
				continue;
			}
			s<<=1;
		}
        else
        {
			if((s<<1|1)>INF)
            {
				st.push('R');
				continue;
			}
            s=s<<1|1;
		}
	}
    write(s);
	return false;
}
